#include <vector>
#include <algorithm>
using namespace std;

long long solve(vector<long long> prices, vector<long long> strategy, long long k) {
    int n = prices.size();
    long long original_profit = 0;
    for (int i = 0; i < n; ++i) {
        original_profit += strategy[i] * prices[i];
    }

    vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + prices[i];
    }

    vector<long long> s_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        s_sum[i + 1] = s_sum[i] + strategy[i] * prices[i];
    }

    long long max_gain = 0;
    long long half_k = k / 2;
    for (int start = 0; start <= n - k; ++start) {
        long long original_window_sum = s_sum[start + k] - s_sum[start];
        long long sum_second_half = prefix_sum[start + k] - prefix_sum[start + half_k];
        long long gain = sum_second_half - original_window_sum;
        if (gain > max_gain) {
            max_gain = gain;
        }
    }

    return original_profit + std::max(0LL, max_gain);
}

